export type TruncateOptions = { ellipsis?: string };

/**
 * Truncate a string by replacing its middle with an ellipsis (or custom marker) so the result length <= maxLength.
 *
 * Rules (see SPEC.md):
 * - If text.length <= maxLength, return text unchanged.
 * - If maxLength <= ellipsis.length, return the ellipsis truncated to maxLength characters.
 * - Otherwise, preserve start and end of the text, placing the ellipsis between them. Start gets ceil(remaining/2)
 *   characters and end gets floor(remaining/2) characters so the total length equals maxLength.
 */
export function truncateMiddle(text: string, maxLength: number, options?: TruncateOptions): string {
  const ellipsis = options?.ellipsis ?? "…"; // default single-character ellipsis

  // Basic type validation
  if (typeof text !== "string") {
    throw new TypeError("text must be a string");
  }
  if (typeof maxLength !== "number" || !Number.isFinite(maxLength) || !Number.isInteger(maxLength)) {
    throw new TypeError("maxLength must be a finite integer");
  }
  if (maxLength < 1) {
    throw new RangeError("maxLength must be >= 1");
  }
  if (typeof ellipsis !== "string") {
    throw new TypeError("options.ellipsis must be a string");
  }

  // If no truncation needed, return original string
  if (text.length <= maxLength) {
    return text;
  }

  // If the ellipsis itself is longer than or equal to maxLength, return a truncated ellipsis
  if (ellipsis.length >= maxLength) {
    return ellipsis.slice(0, maxLength);
  }

  // Number of characters we can keep from original text (excluding the ellipsis)
  const charsToShow = maxLength - ellipsis.length;

  // Split the visible characters between start and end
  const frontChars = Math.ceil(charsToShow / 2);
  const backChars = Math.floor(charsToShow / 2);

  const start = text.slice(0, frontChars);
  const end = text.slice(text.length - backChars);

  return start + ellipsis + end;
}

import { describe, it, expect } from 'vitest';
import { truncateMiddle } from '../src/index';

describe('truncateMiddle', () => {
  it('returns the original text when shorter than maxLength', () => {
    expect(truncateMiddle('short', 10)).toBe('short');
  });

  it('returns the original text when equal to maxLength', () => {
    expect(truncateMiddle('equal', 5)).toBe('equal');
  });

  it('truncates with default ellipsis', () => {
    // 'abcdefg' -> keep 2 at start, 2 at end with 1-char ellipsis -> 'ab…fg'
    expect(truncateMiddle('abcdefg', 5)).toBe('ab…fg');
  });

  it('uses a custom ellipsis', () => {
    expect(truncateMiddle('1234567890', 6, { ellipsis: '..' })).toBe('123..90');
  });

  it('returns truncated ellipsis when ellipsis is longer than maxLength', () => {
    expect(truncateMiddle('longtext', 2, { ellipsis: '...' })).toBe('..');
  });

  it('throws for invalid types', () => {
    // @ts-expect-error intentional misuse
    expect(() => truncateMiddle((123 as unknown) as string, 5)).toThrow(TypeError);
    // @ts-expect-error intentional misuse
    expect(() => truncateMiddle('ok', NaN)).toThrow(TypeError);
  });

  it('throws for maxLength < 1', () => {
    expect(() => truncateMiddle('ok', 0)).toThrow(RangeError);
  });
});
